library;

import 'package:amplify_kinesis/amplify_kinesis.dart';
import 'package:flutter_test/flutter_test.dart';

/// Presence of this file opts the example into the `dart2wasm` E2E leg
/// (`run-wasm: true`) generated by `aft`. It also smoke-tests that the
/// public types build.
void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  group('WASM smoke test', () {
    test('options build', () {
      const options = AmplifyKinesisClientOptions(
        flushStrategy: FlushInterval(interval: Duration(seconds: 10)),
      );
      expect(options.flushStrategy, isA<FlushInterval>());
    });
  });
}
